WaitGameStartState = class("WaitGameStartState", GameState)

function WaitGameStartState:enter()
    self.GameStatus = Define.GameStatus.WaitGameStart

    self.countDownTime = ChampionShipConfig.waitGameStartCountDownTime

    ChampionShipConfig:randomGameStartPos() --打乱数组

    local index = 1
    for _, player in pairs(PlayerManager:getPlayers()) do
        player.birthPos = ChampionShipConfig:getGameStartPos(index)
        player:teleportPosWithYaw1(player.birthPos)
        index = index + 1
    end

    --HostApi.sendPlaySound(0, ChampionShipConfig.waitGameStartMusic1)

    GamePacketSender:sendGameStateInfo(self.GameStatus)
end

function WaitGameStartState:update()
    GamePacketSender:sendWaitGameStartCountDown(self.countDownTime)

    self.countDownTime = self.countDownTime - 1

    if self.countDownTime <= ChampionShipConfig.playMusic2Time then
        HostApi.sendPlaySound(0, ChampionShipConfig.waitGameStartMusic2)
    else
        HostApi.sendPlaySound(0, ChampionShipConfig.waitGameStartMusic1)
    end

    if self.countDownTime <= 0 then
        CageActorConfig:removeAllCageActor()
        ChampionShipConfig:removeCageBlockRegion()
        GameStateManager:changeState(Define.GameStatus.GameRunning)
    end
end

function WaitGameStartState:leave()
    --TODO
end

